css = """
/* styles.css
   Colorful background gradient, full-window canvas sizing,
   and styling for a small overlay UI for the boids page.
*/

/* Root theme variables */
:root{
  --bg-1: #0f172a; /* deep navy */
  --bg-2: #0b3d91; /* rich blue */
  --accent-1: #ff5f6d; /* coral */
  --accent-2: #ffc371; /* warm yellow */
  --glass: rgba(255,255,255,0.06);
  --glass-strong: rgba(255,255,255,0.10);
  --text: #e6eef8;
}

/* Full-viewport base and animated gradient background */
html, body {
  height: 100%;
  margin: 0;
  padding: 0;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: radial-gradient(1200px 600px at 10% 20%, rgba(255,95,109,0.10), transparent 10%),
              radial-gradient(900px 500px at 90% 80%, rgba(255,195,113,0.08), transparent 10%),
              linear-gradient(120deg, var(--bg-1) 0%, var(--bg-2) 60%);
  overflow: hidden;
}

/* subtle animated shift to make the background feel alive */
@keyframes slowShift {
  0% { background-position: 0% 50%, 100% 50%, 0% 0%; }
  50%{ background-position: 50% 50%, 50% 50%, 100% 100%; }
  100%{ background-position: 0% 50%, 100% 50%, 0% 0%; }
}
body {
  background-size: 120% 120%, 140% 140%, 100% 100%;
  animation: slowShift 24s ease-in-out infinite;
}

/* Canvas fills the full window and sits behind the UI */
canvas, #boidsCanvas {
  position: fixed; /* keep canvas pinned while scrolling (none expected) */
  inset: 0; /* top:0; right:0; bottom:0; left:0; */
  width: 100vw;
  height: 100vh;
  display: block;
  background: transparent; /* let the page gradient show through */
  z-index: 0;
}

/* Overlay UI: compact, glass-like control panel */
.overlay {
  position: fixed;
  top: 16px;
  right: 16px;
  z-index: 20;
  background: linear-gradient(180deg, rgba(255,255,255,0.04), rgba(255,255,255,0.02));
  border: 1px solid rgba(255,255,255,0.06);
  backdrop-filter: blur(8px) saturate(120%);
  -webkit-backdrop-filter: blur(8px) saturate(120%);
  color: var(--text);
  padding: 12px;
  border-radius: 10px;
  box-shadow: 0 6px 18px rgba(2,6,23,0.6), inset 0 1px 0 rgba(255,255,255,0.02);
  min-width: 220px;
  max-width: 320px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  font-size: 13px;
}

/* Header inside overlay */
.overlay .title {
  display: flex;
  align-items: center;
  gap: 8px;
}
.overlay .title h3 {
  margin: 0;
  font-size: 14px;
  letter-spacing: 0.2px;
  font-weight: 600;
}
.overlay .title .subtitle {
  margin-left: auto;
  font-size: 11px;
  opacity: 0.85;
}

/* Control rows */
.control-row {
  display: flex;
  align-items: center;
  gap: 8px;
  justify-content: space-between;
}
.control-row label {
  font-size: 12px;
  opacity: 0.95;
  flex: 1;
}
.control-row .control {
  flex: 1.2;
  display: flex;
  align-items: center;
  gap: 8px;
  justify-content: flex-end;
}

/* Range sliders full-width and styled */
input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 6px;
  background: linear-gradient(90deg, var(--accent-1), var(--accent-2));
  border-radius: 999px;
  outline: none;
  cursor: pointer;
}
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: white;
  box-shadow: 0 2px 6px rgba(11,61,145,0.35);
  border: 2px solid rgba(255,255,255,0.9);
}
input[type="range"]::-moz-range-thumb {
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: white;
  border: 2px solid rgba(255,255,255,0.9);
}

/* Toggle / switch */
.switch {
  position: relative;
  width: 46px;
  height: 26px;
  border-radius: 999px;
  background: rgba(255,255,255,0.12);
  border: 1px solid rgba(255,255,255,0.04);
  cursor: pointer;
  flex-shrink: 0;
}
.switch .knob {
  position: absolute;
  top: 3px;
  left: 3px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: white;
  transition: transform 160ms ease;
  box-shadow: 0 2px 6px rgba(2,6,23,0.5);
}
.switch.on {
  background: linear-gradient(90deg, var(--accent-1), var(--accent-2));
}
.switch.on .knob {
  transform: translateX(20px);
}

/* Small buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 8px 10px;
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,0.06);
  background: rgba(255,255,255,0.03);
  color: var(--text);
  font-size: 13px;
  cursor: pointer;
}
.btn.primary {
  background: linear-gradient(90deg, rgba(255,95,109,0.14), rgba(255,195,113,0.10));
  border: 1px solid rgba(255,255,255,0.08);
}
.btn:active { transform: translateY(1px); }

/* Footer / small help text */
.overlay .help {
  font-size: 11px;
  opacity: 0.8;
  color: rgba(230,238,248,0.9);
  margin-top: 4px;
}

/* Responsive adjustments */
@media (max-width: 480px) {
  .overlay {
    left: 12px;
    right: 12px;
    top: 12px;
    min-width: auto;
  }
}

/* Utility: center message when canvas empty */
.centered-message {
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%,-50%);
  z-index: 15;
  background: var(--glass);
  padding: 12px 16px;
  border-radius: 8px;
  border: 1px solid rgba(255,255,255,0.04);
  font-size: 14px;
  color: var(--text);
  text-align: center;
  box-shadow: 0 8px 30px rgba(2,6,23,0.6);
}
"""

